import '../App.js'
import '../App.css';
import img from '../img/DSC_1614.JPG';
import React, { Component, useState } from 'react';
import Product  from './Product.js';

function Banner(props) {
  const [addItem,setAddItem]=useState(0)
 
const add=()=>{
  setAddItem(addItem+1)
  }
  return (
    <div className="banner">
     <>
     <section className='banner'>
      <div className="container">
        <div className='row align-items-center justify-content-between py-5'>
        <h1 >hello my name is {props.value} </h1>
        <h1>{addItem}</h1>

        </div>
  
  <div className='row'>
    <Product imgValue={img} price={12000} add={add}/>
    <Product imgValue={img} price={2000} add={add}/>
    <Product imgValue={img} price={6000} add={add}/>
    <Product imgValue={img} price={8000} add={add}/>

 
  </div>

      </div>
     </section  >
     

     
     
      </>
    </div>
  );
}

export default Banner;
